/**
 * catalog.ts — 2001 template definitions generated by combinator.
 * 801 e-commerce + 1200 website templates.
 * Each entry is a compact config that factory.ts expands into a full SiteDocument.
 */

import type { TemplateCategory } from "./types";
import type { SectionConfig, ProductConfig, TemplateConfig } from "./factory";
import { STYLE_PRESETS } from "./styles";

/* ------------------------------------------------------------------ */
/* CatalogEntry — compact template definition                          */
/* ------------------------------------------------------------------ */

export interface CatalogEntry {
  id: string;
  name: string;
  description: string;
  category: TemplateCategory;
  tags: string[];
  ecommerce: boolean;
  config: Omit<TemplateConfig, "id" | "style">;
  styleIndex: number;
}

/* ------------------------------------------------------------------ */
/* Helper: link                                                        */
/* ------------------------------------------------------------------ */

function L(label: string, href: string, variant: "primary"|"secondary"|"ghost"|"link" = "ghost") {
  return { label, href, variant, external: false };
}

/* ------------------------------------------------------------------ */
/* Section content generators                                          */
/* ------------------------------------------------------------------ */

function heroSec(headline: string, sub: string, isEcom: boolean): SectionConfig {
  return { type: "hero", props: { headline, subheadline: sub,
    ctas: [L(isEcom ? "Shop Now" : "Get Started", isEcom ? "#products" : "#features", "primary"), L("Learn More", "#about", "secondary")]
  }};
}

function featuresSec(items: {icon:string;title:string;description:string}[], v?: string): SectionConfig {
  return { type: "features", variant: v || "grid", props: { title: "Why Choose Us", subtitle: "What makes us different", columns: 3, items }};
}

function testimonialsSec(name: string, v?: string): SectionConfig {
  return { type: "testimonials", variant: v || "cards", props: { title: "What People Say", subtitle: "Trusted by thousands",
    items: [
      { quote: `Love ${name}. Best purchase this year.`, author: "Alex M.", role: "Verified Buyer", rating: 5 },
      { quote: `${name} exceeded all expectations.`, author: "Jordan T.", role: "Loyal Customer", rating: 5 },
      { quote: `I recommend ${name} to everyone.`, author: "Sam R.", role: "Happy Customer", rating: 5 },
    ]
  }};
}

function faqSec(name: string, isEcom: boolean): SectionConfig {
  const items = isEcom
    ? [{ question: "Shipping policy?", answer: "Free standard shipping on orders over $50. Express available at checkout." },
       { question: "Return policy?", answer: "30-day hassle-free returns. Items must be in original condition." },
       { question: "International shipping?", answer: "We ship to 50+ countries. Rates calculated at checkout." },
       { question: `Contact ${name}?`, answer: "Email, phone, or contact form. We respond within 24 hours." }]
    : [{ question: `What is ${name}?`, answer: "We help you achieve more with less effort." },
       { question: "How to get started?", answer: "Sign up free. No credit card required." },
       { question: "What support?", answer: "24/7 email and live chat during business hours." },
       { question: "Free plan?", answer: "Yes, generous free tier. Upgrade anytime." }];
  return { type: "faq", variant: "accordion", props: { title: "FAQ", items }};
}

function ctaSec(sub: string, isEcom: boolean): SectionConfig {
  return { type: "cta", props: { headline: isEcom ? "Start shopping today" : "Ready to get started?", description: sub,
    ctas: [L(isEcom ? "Shop Now" : "Get Started Free", "#", "primary")]
  }};
}

function newsletterSec(name: string): SectionConfig {
  return { type: "newsletter", props: { title: "Stay in the loop", subtitle: `Latest from ${name}. No spam.`, buttonLabel: "Subscribe", placeholder: "Enter your email" }};
}

function logosSec(): SectionConfig {
  return { type: "logos", props: { title: "Trusted by leading brands", grayscale: true, items: [
    { name: "Brand 1", image: { src: "https://images.unsplash.com/photo-placeholder?w=120&h=40&b1", alt: "Brand" }},
    { name: "Brand 2", image: { src: "https://images.unsplash.com/photo-placeholder?w=120&h=40&b2", alt: "Brand" }},
    { name: "Brand 3", image: { src: "https://images.unsplash.com/photo-placeholder?w=120&h=40&b3", alt: "Brand" }},
    { name: "Brand 4", image: { src: "https://images.unsplash.com/photo-placeholder?w=120&h=40&b4", alt: "Brand" }},
  ]}};
}

function metricsSec(isEcom: boolean): SectionConfig {
  const items = isEcom
    ? [{ value: "50K+", label: "Happy Customers", trend: "up" }, { value: "4.9", label: "Average Rating", trend: "up" }, { value: "99%", label: "Satisfaction", trend: "up" }, { value: "24/7", label: "Support" }]
    : [{ value: "10K+", label: "Active Users", trend: "up" }, { value: "99.9%", label: "Uptime", trend: "up" }, { value: "50M+", label: "Tasks Done", trend: "up" }, { value: "150+", label: "Countries" }];
  return { type: "metrics", variant: "grid", props: { title: isEcom ? "By the Numbers" : "Proven Results", items }};
}

function pricingSec(): SectionConfig {
  return { type: "pricing", variant: "cards", props: { title: "Simple Pricing", subtitle: "Choose your plan", columns: 3, items: [
    { name: "Starter", price: 0, period: "month", description: "For individuals", features: ["Up to 3 projects","Basic support","1GB storage"], cta: L("Get Started","#","secondary") },
    { name: "Pro", price: 29, period: "month", description: "For professionals", features: ["Unlimited projects","Priority support","50GB storage","Advanced analytics"], badge: "Popular", cta: L("Start Trial","#","primary") },
    { name: "Enterprise", price: 99, period: "month", description: "For teams", features: ["Everything in Pro","SSO","Unlimited storage","Dedicated support"], cta: L("Contact Sales","#","secondary") },
  ]}};
}

function comparisonSec(name: string): SectionConfig {
  return { type: "comparison", variant: "table", props: { title: `Why ${name}`, subtitle: "See how we compare", plans: [name, "Competitor A", "Competitor B"],
    features: [{ name: "Quality guarantee", values: [true, false, true] }, { name: "Free shipping", values: [true, true, false] }, { name: "24/7 support", values: [true, false, false] }, { name: "Money-back", values: [true, true, true] }]
  }};
}

function teamSec(): SectionConfig {
  return { type: "team", variant: "grid", props: { title: "Meet the Team", subtitle: "The people behind the product", columns: 3,
    members: [{ name: "Alex Rivera", role: "CEO", bio: "Visionary leader.", socials: [] }, { name: "Jordan Lee", role: "CTO", bio: "Full-stack engineer.", socials: [] }, { name: "Sam Chen", role: "Design Lead", bio: "UI craftsperson.", socials: [] }]
  }};
}

function gallerySec(kw: string): SectionConfig {
  return { type: "gallery", variant: "grid", props: { title: "Gallery", columns: 3, items: [
    { image: { src: `https://images.unsplash.com/photo-placeholder?w=600&h=400&${kw}1`, alt: kw }, caption: "Featured" },
    { image: { src: `https://images.unsplash.com/photo-placeholder?w=600&h=400&${kw}2`, alt: kw }, caption: "Latest" },
    { image: { src: `https://images.unsplash.com/photo-placeholder?w=600&h=400&${kw}3`, alt: kw }, caption: "Popular" },
  ]}};
}

function portfolioSec(): SectionConfig {
  return { type: "portfolio", variant: "grid", props: { title: "Our Work", subtitle: "Selected projects", columns: 3, items: [
    { title: "Project Alpha", description: "A flagship project", image: { src: "https://images.unsplash.com/photo-placeholder?w=600&h=400&p1", alt: "Project" }, tags: ["Featured"] },
    { title: "Project Beta", description: "Innovation in action", image: { src: "https://images.unsplash.com/photo-placeholder?w=600&h=400&p2", alt: "Project" }, tags: ["Latest"] },
    { title: "Project Gamma", description: "Award-winning work", image: { src: "https://images.unsplash.com/photo-placeholder?w=600&h=400&p3", alt: "Project" }, tags: ["Award"] },
  ]}};
}

function contactSec(): SectionConfig {
  return { type: "contact", variant: "split", props: { title: "Get in Touch", subtitle: "We would love to hear from you", email: "hello@example.com", phone: "+1 (555) 123-4567", address: "123 Main St, City, ST 12345", submitLabel: "Send Message" }};
}

function timelineSec(name: string): SectionConfig {
  return { type: "timeline", variant: "vertical", props: { title: "Our Journey", items: [
    { date: "2020", title: "Founded", description: `${name} was born.` },
    { date: "2022", title: "Growth", description: "Reached 10,000 customers." },
    { date: "2024", title: "Expansion", description: "Launched in 25 new markets." },
    { date: "2026", title: "Today", description: "Continuing to innovate." },
  ]}};
}

function videoSec(): SectionConfig {
  return { type: "video", props: { title: "See it in Action", videoUrl: "https://www.youtube.com/watch?v=dQw4w9WgXcQ" }};
}

function bannerSec(name: string, isEcom: boolean): SectionConfig {
  return { type: "banner", props: { text: isEcom ? "Free shipping on orders over $50" : `Try ${name} free for 14 days`,
    cta: L(isEcom ? "Shop Now" : "Start Trial", "#", "primary") }};
}

function blogSec(name: string): SectionConfig {
  return { type: "blog", variant: "grid", props: { title: "Latest Articles", subtitle: `Insights from ${name}`, columns: 3, items: [
    { title: "Getting Started Guide", excerpt: "Everything to get started.", date: "2026-06-15", author: "Team" },
    { title: "Tips and Best Practices", excerpt: "Expert tips for maximum value.", date: "2026-06-01", author: "Team" },
    { title: "2026 Industry Trends", excerpt: "What to watch this year.", date: "2026-05-15", author: "Team" },
  ]}};
}

function statsSec(): SectionConfig {
  return { type: "stats", props: { title: "Impact", items: [
    { value: "1M+", label: "Users Worldwide" }, { value: "99.9%", label: "Uptime SLA" }, { value: "500+", label: "Enterprise Clients" }, { value: "24/7", label: "Support" },
  ]}};
}

