/* ------------------------------------------------------------------ */
/* Combinator: niches x styles = 2001 templates                       */
/* ------------------------------------------------------------------ */

function buildCatalog(): CatalogEntry[] {
  const entries: CatalogEntry[] = [];
  const numStyles = STYLE_PRESETS.length;

  // E-commerce: 91 niches × 9 styles each, cap at 801
  for (let i = 0; i < EN.length && entries.length < 801; i++) {
    const n = EN[i];
    const defaultFeats = n.feats.length ? n.feats : [{icon:"zap",title:"Fast",description:"Lightning fast"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
    for (let s = 0; s < 9 && entries.length < 801; s++) {
      const si = s % numStyles;
      const style = STYLE_PRESETS[si];
      const layout = ECOM_LAYOUTS[(i + s) % ECOM_LAYOUTS.length];
      const sections = layout(n.hl, n.sub, n.kw, defaultFeats, true);
      entries.push({
        id: `${n.id}-${style.id}`,
        name: `${n.name} - ${style.name}`,
        description: n.desc,
        category: n.cat,
        tags: [...n.tags, style.id.split("-")[0]],
        ecommerce: true,
        styleIndex: si,
        config: {
          siteName: n.name,
          tagline: n.sub,
          sections,
          products: n.products,
        },
      });
    }
  }

  // Websites: 173 niches × 7-8 styles each, cap at 1200
  for (let i = 0; i < WN.length && entries.length < 2001; i++) {
    const n = WN[i];
    const numPerNiche = i < 3 ? 8 : 7;
    const defaultFeats = [{icon:"zap",title:"Lightning Fast",description:"Built for speed"},{icon:"shield-check",title:"Secure",description:"Enterprise security"},{icon:"sparkles",title:"Beautiful",description:"Stunning design"}];
    for (let s = 0; s < numPerNiche && entries.length < 2001; s++) {
      const si = s % numStyles;
      const style = STYLE_PRESETS[si];
      const layout = WEB_LAYOUTS[(i + s) % WEB_LAYOUTS.length];
      const sections = layout(n.hl, n.sub, n.id.replace(/-/g, " "), defaultFeats, false);
      entries.push({
        id: `${n.id}-${style.id}`,
        name: `${n.name} - ${style.name}`,
        description: n.desc,
        category: n.cat,
        tags: [...n.tags, style.id.split("-")[0]],
        ecommerce: false,
        styleIndex: si,
        config: {
          siteName: n.name,
          tagline: n.sub,
          sections,
        },
      });
    }
  }

  return entries;
}

/** All 2001 catalog entries. Built once on import. */
export const CATALOG: CatalogEntry[] = buildCatalog();